import { Component, OnInit } from '@angular/core';
import { Router } from '@angular/router';
import { DataService, SearchResult } from './data.service';

@Component({
  selector: 'app-home',
  templateUrl: './home.component.html',
  styleUrls: ['./home.component.css'],
})
export class HomeComponent implements OnInit {
  searchInputs = ['', '', ''];
  navSearch = '';
  suggestions: string[] = [];
  activeIndex: number | null = null;
  allKeywords: string[] = [];
  loadingKeywords = false;
  error = '';

  constructor(private router: Router, private dataService: DataService) {}

  ngOnInit(): void {
    this.loadingKeywords = true;
    this.dataService.loadData().subscribe({
      next: () => {
        this.allKeywords = this.dataService.getKeywordsList();
        this.loadingKeywords = false;
      },
      error: () => {
        this.loadingKeywords = false;
      },
    });
  }

  addField(): void {
    if (this.searchInputs.length < 3) {
      this.searchInputs.push('');
    }
  }

  setActiveIndex(index: number): void {
    this.activeIndex = index;
    this.updateSuggestions(index);
  }

  updateSuggestions(index: number): void {
    const value = this.searchInputs[index] || '';
    this.currentSuggestions(value, index);
  }

  currentSuggestions(value: string, index: number): void {
    const query = (value || '').trim().toLowerCase();
    if (!query) {
      this.suggestions = [];
      return;
    }
    this.suggestions = this.allKeywords
      .filter((item) => item.toLowerCase().includes(query))
      .slice(0, 6);
    this.activeIndex = index;
  }

  selectSuggestion(item: string, index: number): void {
    this.searchInputs[index] = item;
    this.suggestions = [];
    this.activeIndex = null;
  }

  doSearch(): void {
    this.error = '';
    const queries = this.searchInputs.map((item) => item.trim()).filter((item) => item);
    if (!queries.length) {
      this.error = 'Inserisci almeno una preoccupazione per iniziare.';
      return;
    }
    this.dataService.loadData().subscribe({
      next: () => {
        const results = this.dataService.findTop3Categories(queries);
        if (!results.length) {
          this.error = 'Nessuna categoria trovata. Prova con parole diverse.';
          return;
        }
        this.router.navigate(['/risultati'], {
          queryParams: { data: JSON.stringify(results) },
        });
      },
      error: () => {
        this.error = 'Errore di rete. Riprova più tardi.';
      },
    });
  }

  searchNav(): void {
    const query = (this.navSearch || '').trim();
    if (!query) {
      return;
    }
    this.searchInputs = [query];
    this.doSearch();
  }
}
<nav class="navbar-custom d-flex align-items-center justify-content-between flex-wrap gap-2">
  <a class="navbar-brand-text text-decoration-none" routerLink="/">🌿 Educazione Digitale Familiare</a>

  <div class="d-flex align-items-center gap-2 flex-wrap">
    <a class="nav-link-custom text-decoration-none me-4" routerLink="#come-funziona">Come funziona</a>
    <a class="nav-link-custom text-decoration-none me-4" routerLink="#esperti">Esperti</a>
    <a class="nav-link-custom text-decoration-none me-4" routerLink="#temi">Temi</a>

    <div class="d-flex gap-2 ms-2 nav-search-wrap">
      <input
        class="search-bar"
        type="search"
        placeholder="Cerca la tua preoccupazione…"
        [(ngModel)]="navSearch"
        (keydown.enter)="searchNav()"
        autocomplete="off"
      />
      <button id="navSearchButton" class="btn-search" (click)="searchNav()">Cerca</button>
    </div>
  </div>
</nav>

<section class="hero">
  <span class="hero-eyebrow">Guida interattiva per genitori</span>

  <h1>
    Naviga il digitale<br />
    <em>insieme alla tua famiglia</em>
  </h1>

  <p class="hero-sub">
    Uno strumento pratico fondato su basi scientifiche: trasforma la teoria pedagogica in regole
    concrete da applicare ogni giorno a casa, per accompagnare i tuoi figli nell'uso consapevole della
    tecnologia.
  </p>

  <div class="hero-cta-group">
    <a class="btn-primary-hero" href="#cerca">Inizia dalla tua preoccupazione</a>
    <a class="btn-secondary-hero" href="#come-funziona">Come funziona →</a>
  </div>
</section>

<section class="search-section" id="cerca">
  <div class="search-section-inner">
    <div class="search-eyebrow">Inizia da qui</div>
    <h2>Qual è la tua preoccupazione?</h2>
    <p>
      Descrivi la situazione con parole tue: ti mostreremo le aree più rilevanti con percorsi pratici.
    </p>

    <div class="multi-search-wrap">
      <div class="search-input-row" *ngFor="let item of searchInputs; let i = index">
        <div class="search-input-layer">
          <input
            class="search-big"
            type="search"
            [placeholder]="i === 0 ? 'es. mio figlio passa troppo tempo sullo smartphone...' : 'Aggiungi una nuova preoccupazione...'
            "
            [(ngModel)]="searchInputs[i]"
            (focus)="setActiveIndex(i)"
            (input)="updateSuggestions(i)"
            autocomplete="off"
          />
          <div class="autocomplete-list" *ngIf="activeIndex === i && suggestions.length">
            <div
              class="autocomplete-item"
              *ngFor="let option of suggestions"
              (mousedown)="selectSuggestion(option, i)"
            >
              {{ option }}
            </div>
          </div>
        </div>
        <button class="btn-add" *ngIf="searchInputs.length < 3 && i === searchInputs.length - 1" (click)="addField()" title="Aggiungi un'altra preoccupazione">+</button>
      </div>
    </div>

    <div class="search-actions">
      <button class="btn-primary-hero" (click)="doSearch()">Cerca →</button>
    </div>

    <div class="search-divider"><span>oppure</span></div>

    <div class="test-banner">
      <div class="test-banner-text">
        <strong>Non sai da dove iniziare?</strong>
        <span>Rispondi a poche domande e scopri le tue aree di attenzione.</span>
      </div>
      <a routerLink="/test" class="btn-secondary-hero">Fai il test →</a>
    </div>

    <p class="error-message" *ngIf="error">{{ error }}</p>
  </div>
</section>

<section class="how-section" id="come-funziona">
  <div class="section-label">Il percorso</div>
  <h2 class="section-title">Dalla preoccupazione alla soluzione</h2>
  <p class="section-sub">Ogni problema viene affrontato con un metodo strutturato in quattro passi.</p>

  <div class="steps-grid">
    <div class="step-card">
      <div class="step-number teal">1</div>
      <h3>Test di valutazione</h3>
      <p>Rispondi a domande mirate per capire la gravità della situazione.</p>
    </div>
    <div class="step-card">
      <div class="step-number amber">2</div>
      <h3>Spiegazione scientifica</h3>
      <p>Comprendi il fenomeno grazie a teorie validate da esperti.</p>
    </div>
    <div class="step-card">
      <div class="step-number coral">3</div>
      <h3>Attività pratiche in famiglia</h3>
      <p>Ricevi attività personalizzate da svolgere insieme ai tuoi figli.</p>
    </div>
    <div class="step-card">
      <div class="step-number gray">4</div>
      <h3>Piano PDF scaricabile</h3>
      <p>Un documento con regole chiare e graduali da tenere a casa.</p>
    </div>
  </div>
</section>

<section class="science-section" id="esperti">
  <div class="science-inner">
    <div class="science-text">
      <div class="section-label">Fondamenti pedagogici</div>
      <h2 class="section-title">Non consigli casuali.<br />Scienza applicata.</h2>
      <p class="section-sub">
        Ogni indicazione è radicata in ricerche riconosciute. Ci affidiamo a metodologie consolidate per offrire strumenti realmente efficaci.
      </p>
    </div>

    <div class="expert-cards">
      <div class="expert-card">
        <div class="expert-name">Serge Tisseron</div>
        <div class="expert-method">Regola 3-6-9-12 · Autoregolazione</div>
        <p class="expert-desc">Psichiatra e psicoanalista francese: definisce le tappe di accesso ai media digitali per età, promuovendo lo sviluppo graduale dell'autocontrollo.</p>
      </div>
      <div class="expert-card">
        <div class="expert-name">Pier Cesare Rivoltella</div>
        <div class="expert-method">Pedagogia dell'Attenzione</div>
        <p class="expert-desc">Professore all'Università Cattolica di Milano: studia come i media influenzano l'attenzione nei minori e le strategie educative più efficaci.</p>
      </div>
      <div class="expert-card">
        <div class="expert-name">Custodi Digitali</div>
        <div class="expert-method">Linee guida preventive</div>
        <p class="expert-desc">Associazione italiana di riferimento per la promozione di un uso sicuro e consapevole delle tecnologie da parte di bambini e ragazzi.</p>
      </div>
    </div>
  </div>
</section>

<section class="topics-section" id="temi">
  <div class="section-label">Aree di intervento</div>
  <h2 class="section-title">Esplora i temi principali</h2>
  <p class="section-sub">Seleziona l'area che ti preoccupa di più per accedere al percorso guidato dedicato.</p>

  <div class="topics-grid">
    <a class="topic-card" href="#">
      <div class="topic-icon" style="background: #E1F5EE;">📱</div>
      <h3>Dipendenza dagli schermi</h3>
      <p>Riconoscere i segnali di uso compulsivo e costruire regole di utilizzo sane e condivise.</p>
      <span class="topic-link">Inizia il percorso →</span>
    </a>
    <a class="topic-card" href="#">
      <div class="topic-icon" style="background: #FAECE7;">🔞</div>
      <h3>Contenuti inappropriati</h3>
      <p>Strategie pratiche per la protezione e il dialogo aperto su ciò che i ragazzi incontrano online.</p>
      <span class="topic-link">Inizia il percorso →</span>
    </a>
    <a class="topic-card" href="#">
      <div class="topic-icon" style="background: #FAEEDA;">🔒</div>
      <h3>Privacy e sicurezza online</h3>
      <p>Educare alla protezione dei dati personali e alle buone pratiche digitali fin da piccoli.</p>
      <span class="topic-link">Inizia il percorso →</span>
    </a>
    <a class="topic-card" href="#">
      <div class="topic-icon" style="background: #E1F5EE;">😔</div>
      <h3>Isolamento sociale</h3>
      <p>Come distinguere relazioni online sane da dinamiche di ritiro dalla vita reale.</p>
      <span class="topic-link">Inizia il percorso →</span>
    </a>
    <a class="topic-card" href="#">
      <div class="topic-icon" style="background: #FAECE7;">💬</div>
      <h3>Social media e cyberbullismo</h3>
      <p>Riconoscere, prevenire e affrontare situazioni di disagio legate all'uso dei social.</p>
      <span class="topic-link">Inizia il percorso →</span>
    </a>
    <a class="topic-card" href="#">
      <div class="topic-icon" style="background: #FAEEDA;">🎮</div>
      <h3>Videogiochi e gaming</h3>
      <p>Regolare il tempo di gioco senza conflitti, valorizzando anche gli aspetti positivi.</p>
      <span class="topic-link">Inizia il percorso →</span>
    </a>
  </div>
</section>

<section class="cta-section">
  <div class="cta-inner">
    <h2>Pronto a iniziare?</h2>
    <p>
      Seleziona la tua preoccupazione, completa il test e ricevi un piano personalizzato in PDF con regole chiare per la tua famiglia.
      Bastano pochi minuti.
    </p>
    <a class="btn-primary-hero" href="#cerca">Trova la tua soluzione</a>
  </div>
</section>
